--
-- Name: check_user_approval_limit(integer, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_user_approval_limit(p_user_id integer, p_amount numeric) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_has_authority BOOLEAN;
BEGIN
    SELECT EXISTS (
        SELECT 1
        FROM users u
        JOIN user_roles ur ON u.id = ur.user_id
        JOIN roles r ON ur.role_id = r.id
        WHERE u.id = p_user_id
        AND r.min_approval_limit <= p_amount
        AND (r.max_approval_limit IS NULL OR r.max_approval_limit >= p_amount)
        AND u.is_active = TRUE
        AND r.is_active = TRUE
    ) INTO v_has_authority;
    
    RETURN v_has_authority;
END;
$$;


