--
-- Name: check_user_system_permission(integer, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_user_system_permission(p_user_id integer, p_system_code character varying, p_required_level character varying DEFAULT 'VIEW'::character varying) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_has_permission BOOLEAN;
BEGIN
    SELECT EXISTS (
        SELECT 1
        FROM users u
        JOIN user_roles ur ON u.id = ur.user_id
        JOIN roles r ON ur.role_id = r.id
        JOIN role_system_permissions rsp ON r.id = rsp.role_id
        JOIN systems s ON rsp.system_id = s.id
        JOIN permission_levels pl ON rsp.permission_level_id = pl.id
        WHERE u.id = p_user_id
        AND s.system_code = p_system_code
        AND pl.priority_order <= (SELECT priority_order FROM permission_levels WHERE level_code = p_required_level)
        AND u.is_active = TRUE
        AND r.is_active = TRUE
        AND rsp.is_active = TRUE
    ) INTO v_has_permission;
    
    RETURN v_has_permission;
END;
$$;


--
-- Name: FUNCTION check_user_system_permission(p_user_id integer, p_system_code character varying, p_required_level character varying); Type: COMMENT; Schema: public; Owner: -
