--
-- Name: get_user_permissions_summary(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_permissions_summary(p_user_id integer) RETURNS TABLE(system_name_ar character varying, system_name_en character varying, permission_level_ar character varying, permission_level_en character varying, allowed_actions text, restrictions text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        s.system_name_ar,
        s.system_name_en,
        pl.level_name_ar,
        pl.level_name_en,
        array_to_string(sp.allowed_actions_ar, ', ') AS allowed_actions,
        array_to_string(sp.restrictions_ar, ', ') AS restrictions
    FROM users u
    JOIN user_roles ur ON u.id = ur.user_id
    JOIN roles r ON ur.role_id = r.id
    JOIN role_system_permissions rsp ON r.id = rsp.role_id
    JOIN systems s ON rsp.system_id = s.id
    JOIN permission_levels pl ON rsp.permission_level_id = pl.id
    LEFT JOIN system_permissions sp ON s.id = sp.system_id AND pl.id = sp.permission_level_id
    WHERE u.id = p_user_id
    AND u.is_active = TRUE
    AND r.is_active = TRUE
    AND rsp.is_active = TRUE
    ORDER BY s.display_order, pl.priority_order;
END;
$$;


