--

CREATE VIEW public.active_tax_settings AS
 SELECT id,
    tax_code,
    tax_name_ar,
    tax_name_en,
    tax_type,
    default_rate,
    COALESCE(branch_specific_rate, default_rate) AS applicable_rate,
    branch_id,
    branch_name_ar,
    applicable_on,
    calculation_method,
    priority
   FROM public.tax_settings t
  WHERE (is_active = true)
  ORDER BY branch_id DESC, priority, tax_name_ar;


