    CONSTRAINT entities_plan_check CHECK (((plan)::text = ANY ((ARRAY['BASIC'::character varying, 'PRO'::character varying, 'ENTERPRISE'::character varying])::text[]))),
    CONSTRAINT entities_status_check CHECK (((status)::text = ANY ((ARRAY['Active'::character varying, 'Inactive'::character varying, 'Suspended'::character varying])::text[]))),
    CONSTRAINT entities_type_check CHECK (((type)::text = ANY ((ARRAY['HQ'::character varying, 'BRANCH'::character varying, 'INCUBATOR'::character varying, 'PLATFORM'::character varying, 'OFFICE'::character varying])::text[])))
);


