--
-- Name: ads_with_source; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.ads_with_source AS
 SELECT a.id,
    a.title,
    a.content,
    a.level,
    a.scope,
    a.status,
    a.ad_source_entity_type,
        CASE
            WHEN (a.hq_id IS NOT NULL) THEN hq.name
            WHEN (a.new_branch_id IS NOT NULL) THEN b.name
            WHEN (a.new_incubator_id IS NOT NULL) THEN i.name
            WHEN (a.new_platform_id IS NOT NULL) THEN p.name
            WHEN (a.new_office_id IS NOT NULL) THEN o.name
            ELSE e.name
        END AS source_entity_name,
    a.cost,
    a.budget,
    a.spent,
    a.impressions,
    a.clicks,
    a.start_date,
    a.end_date,
    a.created_at
   FROM ((((((public.ads a
     LEFT JOIN public.entities e ON (((a.source_entity_id)::text = (e.id)::text)))
     LEFT JOIN public.headquarters hq ON ((a.hq_id = hq.id)))
     LEFT JOIN public.branches b ON ((a.new_branch_id = b.id)))
     LEFT JOIN public.incubators i ON ((a.new_incubator_id = i.id)))
     LEFT JOIN public.platforms p ON ((a.new_platform_id = p.id)))
     LEFT JOIN public.offices o ON ((a.new_office_id = o.id)));


