--
-- Name: audit_log_approvals_chain; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.audit_log_approvals_chain AS
 SELECT al.id AS audit_id,
    al.user_name,
    al.action_type,
    al.entity_reference_name,
    al.approval_status,
    aa.approval_level,
    aa.approver_name,
    aa.approver_role,
    aa.approval_status AS step_status,
    aa.approval_reason,
    aa.approval_comment,
    aa.approval_timestamp
   FROM (public.audit_log al
     LEFT JOIN public.audit_approvals aa ON ((al.id = aa.audit_log_id)))
  ORDER BY al.action_timestamp DESC, aa.approval_level;


