--
-- Name: branch_tax_overrides; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.branch_tax_overrides AS
 SELECT id,
    tax_code,
    tax_name_ar,
    branch_id,
    branch_name_ar,
    default_rate,
    branch_specific_rate,
    (branch_specific_rate - default_rate) AS rate_difference,
    is_active
   FROM public.tax_settings t
  WHERE ((branch_id IS NOT NULL) AND (branch_specific_rate IS NOT NULL))
  ORDER BY branch_id, tax_name_ar;


