--
-- Name: employees; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.employees (
    id integer NOT NULL,
    employee_number character varying(50) NOT NULL,
    full_name character varying(255) NOT NULL,
    email character varying(255),
    phone character varying(50),
    national_id character varying(50),
    "position" character varying(100),
    department character varying(100),
    hq_id integer,
    branch_id integer,
    incubator_id integer,
    platform_id integer,
    office_id integer,
    assigned_entity_type character varying(20) NOT NULL,
    hire_date date,
    salary numeric(10,2),
    employment_type character varying(50),
    is_active boolean DEFAULT true,
    termination_date date,
    address text,
    emergency_contact character varying(255),
    emergency_phone character varying(50),
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT check_employee_single_entity CHECK ((((((
CASE
    WHEN (hq_id IS NOT NULL) THEN 1
    ELSE 0
END +
CASE
    WHEN (branch_id IS NOT NULL) THEN 1
    ELSE 0
END) +
CASE
    WHEN (incubator_id IS NOT NULL) THEN 1
    ELSE 0
END) +
CASE
    WHEN (platform_id IS NOT NULL) THEN 1
    ELSE 0
END) +
CASE
    WHEN (office_id IS NOT NULL) THEN 1
    ELSE 0
END) = 1)),
    CONSTRAINT employees_assigned_entity_type_check CHECK (((assigned_entity_type)::text = ANY ((ARRAY['HQ'::character varying, 'BRANCH'::character varying, 'INCUBATOR'::character varying, 'PLATFORM'::character varying, 'OFFICE'::character varying])::text[]))),
    CONSTRAINT employees_employment_type_check CHECK (((employment_type)::text = ANY ((ARRAY['FULL_TIME'::character varying, 'PART_TIME'::character varying, 'CONTRACT'::character varying, 'INTERN'::character varying])::text[])))
);


