--
-- Name: employees_with_entity; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.employees_with_entity AS
 SELECT emp.id,
    emp.employee_number,
    emp.full_name,
    emp.email,
    emp."position",
    emp.department,
    emp.assigned_entity_type,
        CASE
            WHEN (emp.hq_id IS NOT NULL) THEN hq.name
            WHEN (emp.branch_id IS NOT NULL) THEN b.name
            WHEN (emp.incubator_id IS NOT NULL) THEN i.name
            WHEN (emp.platform_id IS NOT NULL) THEN p.name
            WHEN (emp.office_id IS NOT NULL) THEN o.name
            ELSE NULL::character varying
        END AS entity_name,
        CASE
            WHEN (emp.branch_id IS NOT NULL) THEN b.code
            WHEN (emp.incubator_id IS NOT NULL) THEN i.code
            WHEN (emp.platform_id IS NOT NULL) THEN p.code
            WHEN (emp.office_id IS NOT NULL) THEN o.code
            ELSE NULL::character varying
        END AS entity_code,
    emp.hire_date,
    emp.salary,
    emp.employment_type,
    emp.is_active
   FROM (((((public.employees emp
     LEFT JOIN public.headquarters hq ON ((emp.hq_id = hq.id)))
     LEFT JOIN public.branches b ON ((emp.branch_id = b.id)))
     LEFT JOIN public.incubators i ON ((emp.incubator_id = i.id)))
     LEFT JOIN public.platforms p ON ((emp.platform_id = p.id)))
     LEFT JOIN public.offices o ON ((emp.office_id = o.id)));


