--
-- Name: entity_hierarchy; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.entity_hierarchy AS
 SELECT e.id AS entity_id,
    e.name AS entity_name,
    e.tenant_type,
    e.tenant_id,
    hq.id AS hq_id,
    hq.name AS hq_name,
    hq.code AS hq_code,
    b.id AS branch_id,
    b.name AS branch_name,
    b.code AS branch_code,
    i.id AS incubator_id,
    i.name AS incubator_name,
    i.code AS incubator_code,
    p.id AS platform_id,
    p.name AS platform_name,
    p.code AS platform_code,
    o.id AS office_id,
    o.name AS office_name,
    o.code AS office_code
   FROM (((((public.entities e
     LEFT JOIN public.headquarters hq ON ((e.hq_id = hq.id)))
     LEFT JOIN public.branches b ON ((e.branch_id = b.id)))
     LEFT JOIN public.incubators i ON ((e.incubator_id = i.id)))
     LEFT JOIN public.platforms p ON ((e.platform_id = p.id)))
     LEFT JOIN public.offices o ON ((e.office_id = o.id)));


