--
-- Name: invoices; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.invoices (
    id character varying(50) NOT NULL,
    entity_id character varying(20),
    type character varying(20) NOT NULL,
    title character varying(255) NOT NULL,
    amount numeric(10,2) NOT NULL,
    paid_amount numeric(10,2) DEFAULT 0.00,
    status character varying(20) DEFAULT 'UNPAID'::character varying,
    issue_date date NOT NULL,
    due_date date NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    updated_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    requires_approval boolean DEFAULT false,
    approval_workflow_id integer,
    approval_status character varying(20) DEFAULT 'NOT_REQUIRED'::character varying,
    user_id integer,
    branch_id integer,
    office_id integer,
    incubator_id integer,
    issuer_entity_type character varying(20),
    beneficiary_id integer,
    customer_name character varying(255),
    customer_phone character varying(20),
    customer_number character varying(50),
    customer_email character varying(255),
    payment_method character varying(255),
    payment_status character varying(50) DEFAULT 'UNPAID'::character varying,
    payment_type character varying(50) DEFAULT 'NONE'::character varying,
    total_tax numeric(15,2) DEFAULT 0.00,
    total_after_tax numeric(15,2),
    currency character varying(10) DEFAULT 'SAR'::character varying,
    country_code character varying(10) DEFAULT 'SA'::character varying,
    platform_id uuid,
    CONSTRAINT invoices_approval_status_check CHECK (((approval_status)::text = ANY ((ARRAY['NOT_REQUIRED'::character varying, 'PENDING'::character varying, 'APPROVED'::character varying, 'REJECTED'::character varying])::text[]))),
    CONSTRAINT invoices_issuer_entity_type_check CHECK (((issuer_entity_type)::text = ANY ((ARRAY['BRANCH'::character varying, 'INCUBATOR'::character varying, 'OFFICE'::character varying, 'PLATFORM'::character varying])::text[]))),
    CONSTRAINT invoices_status_check CHECK (((status)::text = ANY ((ARRAY['PAID'::character varying, 'PARTIAL'::character varying, 'UNPAID'::character varying, 'OVERDUE'::character varying])::text[]))),
    CONSTRAINT invoices_type_check CHECK (((type)::text = ANY ((ARRAY['SUBSCRIPTION'::character varying, 'SERVICE'::character varying, 'CUSTOM'::character varying])::text[])))
);


