    CONSTRAINT check_user_entity_link CHECK (((branch_id IS NOT NULL) OR (incubator_id IS NOT NULL) OR (platform_id IS NOT NULL) OR (office_id IS NOT NULL) OR (entity_id IS NOT NULL))),
    CONSTRAINT users_linked_entity_type_check CHECK (((linked_entity_type)::text = ANY ((ARRAY['BRANCH'::character varying, 'INCUBATOR'::character varying, 'PLATFORM'::character varying, 'OFFICE'::character varying])::text[])))
);


