--
-- Name: invoices_with_details; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.invoices_with_details AS
 SELECT inv.id,
    inv.entity_id AS old_entity_id,
    inv.type,
    inv.title,
    inv.amount,
    inv.paid_amount,
    inv.status,
    inv.issue_date,
    inv.due_date,
    inv.issuer_entity_type,
    u.name AS customer_name,
    u.email AS customer_email,
        CASE
            WHEN (inv.branch_id IS NOT NULL) THEN b.name
            WHEN (inv.office_id IS NOT NULL) THEN o.name
            WHEN (inv.incubator_id IS NOT NULL) THEN i.name
            ELSE e.name
        END AS issuer_entity_name,
    inv.created_at
   FROM (((((public.invoices inv
     LEFT JOIN public.users u ON ((inv.user_id = u.id)))
     LEFT JOIN public.entities e ON (((inv.entity_id)::text = (e.id)::text)))
     LEFT JOIN public.branches b ON ((inv.branch_id = b.id)))
     LEFT JOIN public.offices o ON ((inv.office_id = o.id)))
     LEFT JOIN public.incubators i ON ((inv.incubator_id = i.id)));


