--
-- Name: users_with_entity; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.users_with_entity AS
 SELECT u.id,
    u.name,
    u.email,
    u.role,
    u.tenant_type,
    u.entity_id AS old_entity_id,
    u.linked_entity_type,
        CASE
            WHEN (u.branch_id IS NOT NULL) THEN b.name
            WHEN (u.incubator_id IS NOT NULL) THEN i.name
            WHEN (u.platform_id IS NOT NULL) THEN p.name
            WHEN (u.office_id IS NOT NULL) THEN o.name
            ELSE e.name
        END AS entity_name,
        CASE
            WHEN (u.branch_id IS NOT NULL) THEN b.code
            WHEN (u.incubator_id IS NOT NULL) THEN i.code
            WHEN (u.platform_id IS NOT NULL) THEN p.code
            WHEN (u.office_id IS NOT NULL) THEN o.code
            ELSE NULL::character varying
        END AS entity_code,
    u.branch_id,
    u.incubator_id,
    u.platform_id,
    u.office_id,
    u.is_active,
    u.created_at
   FROM (((((public.users u
     LEFT JOIN public.entities e ON (((u.entity_id)::text = (e.id)::text)))
     LEFT JOIN public.branches b ON ((u.branch_id = b.id)))
     LEFT JOIN public.incubators i ON ((u.incubator_id = i.id)))
     LEFT JOIN public.platforms p ON ((u.platform_id = p.id)))
     LEFT JOIN public.offices o ON ((u.office_id = o.id)));


